exercise.solutionCode:
public class Main {
    public static void main(String[] args) {
        double principal  = 100000.0;
        double annualRate = 0.12;
        int    months     = 12;

        double interest   = principal * annualRate;
        double total      = principal + interest;
        double emi        = total / months;
        long   roundedEmi = Math.round(emi);

        System.out.printf("Principal : Rs %.2f%n", principal);
        System.out.printf("Interest  : Rs %.2f%n", interest);
        System.out.printf("Total     : Rs %.2f%n", total);
        System.out.printf("EMI       : Rs %d%n",   roundedEmi);
    }
}
